{
  "$schema": "https://metaharness.dev/schemas/mcp-policy.v1.json",
  "name": "@metaharness/example-huggingface",
  "version": "1.0.0",
  "description": "Default-deny MCP policy for the HuggingFace Inference API showcase harness. Read and safe-fetch tools are granted; all writes and mutations require --allow-mutations.",
  "defaultDeny": true,
  "mutations_require_flag": "--allow-mutations",
  "audit_log": ".harness/audit.log",
  "toolTimeoutMs": 30000,
  "maxToolCallsPerTurn": 12,
  "grants": [
    {
      "tool": "Read",
      "scope": "**",
      "reason": "Agents need to read project files, plans, and prior executor output."
    },
    {
      "tool": "Bash",
      "pattern": "node *",
      "reason": "Executor runs the @huggingface/inference SDK via Node scripts (read-only calls; HF_SANDBOX=true by default)."
    },
    {
      "tool": "Bash",
      "pattern": "cat *",
      "reason": "Planner and verifier inspect plan files."
    },
    {
      "tool": "Bash",
      "pattern": "echo *",
      "reason": "Debugging and pipeline status output."
    },
    {
      "tool": "WebFetch",
      "scope": "https://huggingface.co/**",
      "reason": "Planner fetches model cards (GET only) to confirm model ID and task type."
    },
    {
      "tool": "WebFetch",
      "scope": "https://api-inference.huggingface.co/**",
      "reason": "Executor reads inference API responses; actual POST calls are made by the SDK inside Node, not directly by this tool."
    }
  ],
  "denied": [
    {
      "tool": "Write",
      "reason": "File writes require --allow-mutations."
    },
    {
      "tool": "Edit",
      "reason": "File edits require --allow-mutations."
    },
    {
      "tool": "Bash",
      "pattern": "curl *",
      "reason": "Use WebFetch instead of raw curl. Denied unconditionally."
    },
    {
      "tool": "Bash",
      "pattern": "rm *",
      "reason": "Destructive shell commands are never granted.",
      "never": true
    },
    {
      "tool": "Bash",
      "pattern": "sudo *",
      "reason": "Privilege escalation is never granted.",
      "never": true
    },
    {
      "tool": "Bash",
      "pattern": "dd *",
      "reason": "Raw device writes are never granted.",
      "never": true
    }
  ],
  "allowedWithFlag": [
    {
      "flag": "--allow-mutations",
      "tools": ["Write", "Edit"],
      "reason": "Mutations (writing results to disk) are intentionally opt-in. Pass --allow-mutations to /hf-infer to unlock."
    },
    {
      "flag": "--allow-mutations",
      "tools": ["Bash"],
      "patterns": ["npm install *"],
      "reason": "Package installs modify node_modules and require explicit opt-in."
    }
  ],
  "requireApprovalForDangerous": true,
  "notes": [
    "HF_SANDBOX=true (default in .env.example) causes the executor to log API calls without sending them. Set HF_SANDBOX=false for live inference.",
    "The verifier must return PASS before any result is surfaced. A FAIL result stops the pipeline.",
    "All tool calls are appended to audit_log. The audit log is never deleted by the harness."
  ]
}
